def ground_truth_process_graph(graph_data):

    # Initialize color mapping
    color_map = []

    # Initialize virtual networks counter
    vn_counter = 0

    # Traverse the graph
    for node in graph_data:

        # Check if node type is 'virtualnetworks'
        if graph_data.nodes[node]['type'] == 'virtualnetworks':
            vn_counter += 1

            # Color nodes according to the counter
            if vn_counter % 2 == 0:
                color_map.append('red')
            else:
                color_map.append('blue')
        else:
            color_map.append('black')

    # Assign color to each node
    nx.set_node_attributes(graph_data, {node: color for node, color in zip(graph_data, color_map)}, 'color')

    return_object = {
        'type': 'graph',
        'data': graph_data
    }

    return return_object

